ux_patterns:
{
  "patterns": [
    {
      "name": "Three-Column Adaptive Layout",
      "category": "layout",
      "description": "Primary layout with collapsible left sidebar (200-300px), flexible main content area, and right inspector panel (250-350px). Panels can be docked, undocked, and resized with drag handles. Main area takes remaining space with minimum 400px width.",
      "implementation_notes": "Use CSS Grid for main structure, ResizeObserver for drag handles, localStorage for panel state persistence. Implement snap-to positions at 25% increments. Add keyboard shortcuts (Ctrl+1,2,3) to toggle panels.",
      "priority": "high"
    },
    {
      "name": "Command Palette with Fuzzy Search",
      "category": "shortcuts",
      "description": "Cmd/Ctrl+K opens overlay with fuzzy search across all actions, settings, and navigation. Shows recent actions, keyboard shortcuts, and contextual suggestions based on current tool/mode.",
      "implementation_notes": "Use libraries like Fuse.js for fuzzy search. Implement debounced input with 150ms delay. Cache recent actions (last 10) and weight by frequency. Support arrow navigation and Enter/Escape handling.",
      "priority": "high"
    },
    {
      "name": "Engineering Parameter Forms",
      "category": "forms",
      "description": "Two-column grid layout for related parameters with integrated unit dropdowns, scientific notation support, and real-time validation. Group related parameters in collapsible sections with clear visual hierarchy.",
      "implementation_notes": "Use controlled inputs with number formatters (1e-3, 1.23GHz). Implement unit conversion logic. Show validation states with red borders and error icons. Use fieldset grouping with legend labels. Support tab navigation between fields.",
      "priority": "high"
    },
    {
      "name": "Multi-Chart Visualization Dashboard",
      "category": "viz",
      "description": "Side-by-side chart layout with synchronized zoom/pan, crosshair cursors, and responsive sizing. Support S11/S21 plots, Smith charts, and 3D radiation patterns with consistent styling and interactions.",
      "implementation_notes": "Use Chart.js or D3.js with custom themes. Implement chart synchronization via event bus. Add resize observers for responsive behavior. Include export functionality (PNG, SVG, CSV). Minimum chart size 300x200px.",
      "priority": "high"
    },
    {
      "name": "3D Viewport with Tool Overlay",
      "category": "viewport",
      "description": "Full 3D scene with floating toolbar overlay (top-right), view cube gizmo (top-left), and grid snap controls. Include view presets (front, back, top, iso) and measurement tools with heads-up display.",
      "implementation_notes": "Use Three.js with OrbitControls. Position overlays with absolute positioning and z-index layering. Implement view transitions with easing. Add keyboard shortcuts for view presets (1-6 keys). Include wireframe/solid toggle.",
      "priority": "high"
    },
    {
      "name": "Collapsible Panel System",
      "category": "panels",
      "description": "Accordion-style panels with chevron indicators, smooth animations, and scrollable content areas. Fixed headers remain visible during scroll with clear section dividers and optional search within panels.",
      "implementation_notes": "Use CSS transitions with max-height for smooth collapse. Implement virtual scrolling for large lists. Add search functionality with highlight matching. Use sticky headers with box-shadow for depth. Support Ctrl+F for in-panel search.",
      "priority": "medium"
    },
    {
      "name": "Engineering Workflow Shortcuts",
      "category": "shortcuts",
      "description": "Essential keyboard shortcuts: Ctrl+R (run simulation), Space (pause/resume), Ctrl+Shift+S (quick save), F5 (refresh results), Ctrl+D (duplicate element), Delete (remove selected), Ctrl+Z/Y (undo/redo).",
      "implementation_notes": "Implement global hotkey manager with event.preventDefault() for overrides. Show shortcuts in tooltips and context menus. Support chord combinations (Ctrl+Shift+...). Add shortcut customization in settings.",
      "priority": "high"
    },
    {
      "name": "Toast Notification System",
      "category": "layout",
      "description": "Non-blocking toast notifications positioned top-right with auto-dismiss timers. Include progress bars for long operations, error states with retry actions, and success confirmations with undo options where applicable.",
      "implementation_notes": "Use z-index 1000+ for overlay. Implement queue system with max 3 visible toasts. Add slide-in animations from right. Support click-to-dismiss and auto-dismiss after 5s (errors persist). Include notification sound toggle.",
      "priority": "medium"
    },
    {
      "name": "Dark Theme Color System",
      "category": "theme",
      "description": "Dark theme with proper contrast ratios (4.5:1 minimum), blue accent color (#3B82F6), surface hierarchy using gray scales (900-700), and semantic colors for success/warning/error states.",
      "implementation_notes": "Use CSS custom properties for theme variables. Implement surface levels: bg-gray-900 (base), bg-gray-800 (raised), bg-gray-700 (overlay). Ensure WCAG AA compliance. Add theme toggle with system preference detection.",
      "priority": "high"
    },
    {
      "name": "Responsive Breakpoint System",
      "category": "layout",
      "description": "Minimum application width 1024px, with panel collapse at 1200px breakpoint. Sidebar collapses to icon-only at narrow widths, inspector panel moves to overlay mode below 1400px. Main content maintains 400px minimum.",
      "implementation_notes": "Use Tailwind breakpoint system with custom values. Implement useMediaQuery hook for React components. Store collapsed states in localStorage. Add smooth transitions for panel state changes. Support fullscreen mode (F11).",
      "priority": "medium"
    },
    {
      "name": "Status Bar with Simulation State",
      "category": "layout",
      "description": "Fixed bottom status bar showing current simulation status, progress indicators, memory usage, and active tool information. Include error counts and quick access to log viewer.",
      "implementation_notes": "Position fixed at bottom with height 32px. Use flexbox for status sections. Update progress via WebWorker messages. Add click handlers for detailed views. Include expandable error panel on error count click.",
      "priority": "medium"
    },
    {
      "name": "Context Menu System",
      "category": "shortcuts",
      "description": "Right-click context menus with relevant actions based on selected objects/tools. Include separator lines, disabled states, and keyboard shortcut hints. Support nested menus for complex operations.",
      "implementation_notes": "Position absolutely based on mouse coordinates. Implement boundary detection to prevent overflow. Use semantic HTML with role attributes. Add keyboard navigation with arrow keys. Close on outside click or Escape key.",
      "priority": "medium"
    },
    {
      "name": "Drag-and-Drop Interface",
      "category": "layout",
      "description": "Support dragging components from sidebar to 3D viewport, reordering items in lists, and file drop for importing geometries. Provide visual feedback with ghost images and drop zones.",
      "implementation_notes": "Use HTML5 drag-and-drop API with custom drag images. Implement drop zone highlighting with dashed borders. Add haptic feedback on successful drops. Support multiple file types (STL, STEP, etc.).",
      "priority": "low"
    },
    {
      "name": "Undo/Redo History Panel",
      "category": "panels",
      "description": "Visual history stack showing recent actions with timestamps, allowing selective undo to specific points. Include action grouping for complex operations and branch visualization for non-linear history.",
      "implementation_notes": "Implement command pattern with action objects. Store max 50 actions in memory. Use tree visualization for branched history. Add search/filter for specific action types. Support bulk operations on history items.",
      "priority": "low"
    },
    {
      "name": "Loading States and Skeletons",
      "category": "layout",
      "description": "Skeleton loading states for charts, 3D viewport, and data tables. Include shimmer animations and progressive loading indicators. Maintain layout stability during content loading.",
      "implementation_notes": "Create skeleton components matching final content dimensions. Use CSS animations for shimmer effects. Implement progressive enhancement pattern. Add timeout handling for failed loads with retry options.",
      "priority": "low"
    }
  ]
}

design_brief:
{
  "layout_strategy": {
    "structure": "3-column",
    "sidebar_width": "280px",
    "sidebar_min_width": "240px",
    "main_content_min_width": "600px",
    "right_panel_width": "320px",
    "dividers": {
      "resizable": true,
      "width": "1px",
      "drag_handle_width": "8px"
    },
    "header_height": "56px",
    "footer_height": "40px"
  },
  "spacing_system": {
    "base": 4,
    "scale": {
      "xs": "4px",
      "sm": "8px",
      "md": "16px",
      "lg": "24px",
      "xl": "32px",
      "2xl": "48px"
    },
    "usage_rules": {
      "xs": "icon padding, tight spacing",
      "sm": "button padding, input padding",
      "md": "component margins, card padding",
      "lg": "section spacing, panel margins",
      "xl": "major section separation",
      "2xl": "page-level spacing"
    }
  },
  "typography": {
    "font_family": "'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif",
    "scale": {
      "h1": {
        "size": "24px",
        "weight": 600,
        "line_height": "32px"
      },
      "h2": {
        "size": "20px",
        "weight": 600,
        "line_height": "28px"
      },
      "h3": {
        "size": "16px",
        "weight": 600,
        "line_height": "24px"
      },
      "body": {
        "size": "14px",
        "weight": 400,
        "line_height": "20px"
      },
      "body_small": {
        "size": "12px",
        "weight": 400,
        "line_height": "16px"
      },
      "label": {
        "size": "12px",
        "weight": 500,
        "line_height": "16px"
      },
      "caption": {
        "size": "11px",
        "weight": 400,
        "line_height": "14px"
      }
    }
  },
  "color_tokens": {
    "backgrounds": {
      "primary": "#ffffff",
      "secondary": "#f8f9fa",
      "tertiary": "#f1f3f4",
      "quaternary": "#e8eaed",
      "dark": "#1a1a1a",
      "sidebar": "#f8f9fa",
      "panel": "#ffffff"
    },
    "borders": {
      "light": "#e8eaed",
      "medium": "#dadce0",
      "strong": "#9aa0a6"
    },
    "text": {
      "primary": "#202124",
      "secondary": "#5f6368",
      "tertiary": "#80868b",
      "disabled": "#9aa0a6",
      "inverse": "#ffffff"
    },
    "accent": {
      "primary": "#1976d2",
      "primary_hover": "#1565c0",
      "primary_active": "#0d47a1"
    },
    "status": {
      "success": "#0d8043",
      "warning": "#ea8600",
      "error": "#d32f2f",
      "info": "#1976d2"
    },
    "chart_palette": [
      "#1976d2",
      "#dc004e",
      "#0d8043",
      "#ea8600",
      "#7b1fa2",
      "#0097a7",
      "#bf360c",
      "#558b2f"
    ]
  },
  "component_sizes": {
    "inputs": {
      "height": "36px",
      "padding": "8px 12px"
    },
    "buttons": {
      "small": {
        "height": "32px",
        "padding": "6px 12px",
        "font_size": "12px"
      },
      "medium": {
        "height": "36px",
        "padding": "8px 16px",
        "font_size": "14px"
      },
      "large": {
        "height": "44px",
        "padding": "12px 24px",
        "font_size": "16px"
      }
    },
    "icons": {
      "small": "16px",
      "medium": "20px",
      "large": "24px"
    },
    "border_radius": {
      "small": "4px",
      "medium": "6px",
      "large": "8px"
    }
  },
  "interactive_states": {
    "buttons": {
      "hover": {
        "background_opacity": 0.08,
        "transition": "all 150ms ease"
      },
      "focus": {
        "outline": "2px solid #1976d2",
        "outline_offset": "2px"
      },
      "active": {
        "background_opacity": 0.12,
        "transform": "scale(0.98)"
      },
      "disabled": {
        "opacity": 0.5,
        "cursor": "not-allowed"
      }
    },
    "inputs": {
      "hover": {
        "border_color": "#9aa0a6"
      },
      "focus": {
        "border_color": "#1976d2",
        "box_shadow": "0 0 0 2px rgba(25, 118, 210, 0.2)"
      },
      "disabled": {
        "background_color": "#f1f3f4",
        "opacity": 0.7
      }
    },
    "navigation": {
      "hover": {
        "background_color": "rgba(25, 118, 210, 0.04)"
      },
      "active": {
        "background_color": "rgba(25, 118, 210, 0.08)",
        "border_left": "3px solid #1976d2"
      }
    }
  },
  "shadows": {
    "small": "0 1px 3px rgba(0, 0, 0, 0.12), 0 1px 2px rgba(0, 0, 0, 0.24)",
    "medium": "0 3px 6px rgba(0, 0, 0, 0.15), 0 2px 4px rgba(0, 0, 0, 0.12)",
    "large": "0 10px 20px rgba(0, 0, 0, 0.15), 0 3px 6px rgba(0, 0, 0, 0.10)",
    "modal": "0 25px 50px rgba(0, 0, 0, 0.25)"
  },
  "panel_system": {
    "collapsible_sections": {
      "animation_duration": "200ms",
      "easing": "ease-out"
    },
    "header_height": "48px",
    "footer_height": "40px",
    "scroll_behavior": {
      "type": "custom",
      "track_width": "8px",
      "thumb_radius": "4px"
    },
    "panel_padding": "16px",
    "section_spacing": "24px"
  },
  "responsive_rules": {
    "breakpoints": {
      "tablet": "768px",
      "desktop": "1024px"
    },
    "sidebar": {
      "min_width": "240px",
      "collapse_at": "768px",
      "mobile_overlay": true
    },
    "panel_priorities": [
      "main_content",
      "sidebar",
      "right_panel"
    ],
    "right_panel_collapse": "1200px"
  },
  "priority_changes": [
    {
      "change": "Implement unified spacing system with 4px base unit",
      "impact": "high",
      "effort": "medium"
    },
    {
      "change": "Update color palette with proper semantic tokens",
      "impact": "high",
      "effort": "small"
    },
    {
      "change": "Replace system fonts with Inter typography",
      "impact": "medium",
      "effort": "small"
    },
    {
      "change": "Add consistent interactive states across all components",
      "impact": "high",
      "effort": "medium"
    },
    {
      "change": "Implement proper visual hierarchy with typography scale",
      "impact": "high",
      "effort": "small"
    },
    {
      "change": "Add elevation system with consistent shadows",
      "impact": "medium",
      "effort": "small"
    },
    {
      "change": "Implement resizable panel system with proper constraints",
      "impact": "medium",
      "effort": "large"
    },
    {
      "change": "Add responsive behavior for mobile and tablet viewports",
      "impact": "high",
      "effort": "large"
    },
    {
      "change": "Create loading states and skeleton screens",
      "impact": "medium",
      "effort": "medium"
    },
    {
      "change": "Implement accessible focus management and keyboard navigation",
      "impact": "medium",
      "effort": "medium"
    }
  ]
}
